import{_ as e,o as l,c as a,a4 as n}from"./chunks/framework._in6GHBg.js";const p=JSON.parse('{"title":"古诗词鉴赏三步法","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/tip-poetry.md","filePath":"chinese/tip-poetry.md"}'),r={name:"chinese/tip-poetry.md"};function i(s,t,o,d,h,c){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="古诗词鉴赏三步法" tabindex="-1">古诗词鉴赏三步法 <a class="header-anchor" href="#古诗词鉴赏三步法" aria-label="Permalink to &quot;古诗词鉴赏三步法&quot;">​</a></h1><p><strong>从&quot;看不懂&quot;到&quot;能答题&quot;——10分钟掌握古诗词鉴赏</strong></p><hr><h2 id="痛点" tabindex="-1">痛点 <a class="header-anchor" href="#痛点" aria-label="Permalink to &quot;痛点&quot;">​</a></h2><ul><li>古诗词读不懂，不知道在说什么</li><li>看懂了字面意思，但不知道表达了什么情感</li><li>知道情感，但不会组织语言答题</li></ul><hr><h2 id="三步法" tabindex="-1">三步法 <a class="header-anchor" href="#三步法" aria-label="Permalink to &quot;三步法&quot;">​</a></h2><h3 id="第一步-读题目-定方向-1分钟" tabindex="-1">第一步：读题目，定方向（1分钟） <a class="header-anchor" href="#第一步-读题目-定方向-1分钟" aria-label="Permalink to &quot;第一步：读题目，定方向（1分钟）&quot;">​</a></h3><p><strong>看什么</strong>：</p><ul><li>诗题（往往点明内容或情感）</li><li>作者（了解风格：李白豪放、杜甫沉郁、李清照婉约）</li><li>注释（背景信息，必看）</li></ul><p><strong>示例</strong>：</p><blockquote><p>《春望》杜甫 注释：此诗作于安史之乱期间，杜甫被困长安。</p></blockquote><p><strong>推断</strong>：战乱背景→ likely 忧国忧民、思乡怀人</p><hr><h3 id="第二步-抓关键词-析情感-3分钟" tabindex="-1">第二步：抓关键词，析情感（3分钟） <a class="header-anchor" href="#第二步-抓关键词-析情感-3分钟" aria-label="Permalink to &quot;第二步：抓关键词，析情感（3分钟）&quot;">​</a></h3><p><strong>找什么</strong>：</p><ul><li><strong>意象词</strong>：月、柳、雁、杜鹃（承载情感的具体事物）</li><li><strong>情感词</strong>：愁、恨、喜、悲（直接表达情感）</li><li><strong>动作词</strong>：望、思、归、愁（暗示心理状态）</li></ul><p><strong>常见意象对应情感</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">意象</th><th style="text-align:left;">常见情感</th></tr></thead><tbody><tr><td style="text-align:center;">月</td><td style="text-align:left;">思乡、团圆、孤独</td></tr><tr><td style="text-align:center;">柳</td><td style="text-align:left;">离别、挽留</td></tr><tr><td style="text-align:center;">雁</td><td style="text-align:left;">思乡、书信、归乡</td></tr><tr><td style="text-align:center;">杜鹃</td><td style="text-align:left;">哀愁、思归</td></tr><tr><td style="text-align:center;">梧桐</td><td style="text-align:left;">凄凉、悲伤</td></tr><tr><td style="text-align:center;">鸿鹄</td><td style="text-align:left;">志向、抱负</td></tr></tbody></table><p><strong>示例</strong>：《春望》</p><ul><li>意象：草木、花、鸟、烽火、家书</li><li>情感词：破、深、溅泪、惊心、恨、白头</li><li>推断：国破家亡之痛，思家忧国之愁</li></ul><hr><h3 id="第三步-套模板-写答案-2分钟" tabindex="-1">第三步：套模板，写答案（2分钟） <a class="header-anchor" href="#第三步-套模板-写答案-2分钟" aria-label="Permalink to &quot;第三步：套模板，写答案（2分钟）&quot;">​</a></h3><p><strong>鉴赏题答题模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这首诗通过描写[意象/景象]，</span></span>
<span class="line"><span>运用了[手法]，</span></span>
<span class="line"><span>营造了一种[氛围/意境]，</span></span>
<span class="line"><span>表达了诗人[情感/志向]。</span></span></code></pre></div><p><strong>手法词汇表</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">手法</th><th style="text-align:center;">识别标志</th><th style="text-align:center;">效果词</th></tr></thead><tbody><tr><td style="text-align:center;">比喻</td><td style="text-align:center;">像、如、似</td><td style="text-align:center;">生动形象</td></tr><tr><td style="text-align:center;">拟人</td><td style="text-align:center;">物有了人的动作情感</td><td style="text-align:center;">生动活泼</td></tr><tr><td style="text-align:center;">对比</td><td style="text-align:center;">两个相反事物对照</td><td style="text-align:center;">突出强调</td></tr><tr><td style="text-align:center;">借景抒情</td><td style="text-align:center;">景物描写后接情感</td><td style="text-align:center;">情景交融</td></tr><tr><td style="text-align:center;">用典</td><td style="text-align:center;">历史人物/故事</td><td style="text-align:center;">含蓄委婉</td></tr><tr><td style="text-align:center;">虚实结合</td><td style="text-align:center;">想象与现实交织</td><td style="text-align:center;">丰富意境</td></tr></tbody></table><p><strong>示例答案</strong>：《春望》</p><blockquote><p>这首诗通过描写国都沦陷后草木丛生的荒凉景象，运用拟人手法（花溅泪、鸟惊心），营造了凄凉悲伤的意境，表达了诗人忧国思家、感时伤怀的沉痛心情。</p></blockquote><hr><h2 id="常见题型速答" tabindex="-1">常见题型速答 <a class="header-anchor" href="#常见题型速答" aria-label="Permalink to &quot;常见题型速答&quot;">​</a></h2><h3 id="题型1-这首诗表达了什么情感" tabindex="-1">题型1：这首诗表达了什么情感？ <a class="header-anchor" href="#题型1-这首诗表达了什么情感" aria-label="Permalink to &quot;题型1：这首诗表达了什么情感？&quot;">​</a></h3><p><strong>答法</strong>：</p><ul><li>忧国忧民类：忧国伤时、怀才不遇、报国无门</li><li>思乡怀人类：思念故乡、怀念亲友、离别之苦</li><li>人生感慨类：时光易逝、壮志难酬、归隐田园</li><li>边塞征战类：建功立业、思乡厌战、壮志豪情</li></ul><h3 id="题型2-某句妙在何处" tabindex="-1">题型2：某句妙在何处？ <a class="header-anchor" href="#题型2-某句妙在何处" aria-label="Permalink to &quot;题型2：某句妙在何处？&quot;">​</a></h3><p><strong>答法</strong>：</p><ol><li>解释句意</li><li>指出手法</li><li>分析效果</li><li>点明情感</li></ol><h3 id="题型3-炼字题-某字用得好-为什么" tabindex="-1">题型3：炼字题（某字用得好，为什么？） <a class="header-anchor" href="#题型3-炼字题-某字用得好-为什么" aria-label="Permalink to &quot;题型3：炼字题（某字用得好，为什么？）&quot;">​</a></h3><p><strong>答法</strong>：</p><ol><li>解释字义</li><li>描述景象</li><li>点出效果</li><li>表达情感</li></ol><hr><h2 id="实战演练" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练" aria-label="Permalink to &quot;实战演练&quot;">​</a></h2><p><strong>练习</strong>：《静夜思》李白</p><blockquote><p>床前明月光，疑是地上霜。 举头望明月，低头思故乡。</p></blockquote><p><strong>三步分析</strong>：</p><ol><li>题目《静夜思》→ 夜晚思乡</li><li>意象：明月、霜；动作：望、思；情感：故乡</li><li>答案：这首诗通过描写秋夜月光如霜的景象，运用比喻手法，营造了清冷寂静的意境，表达了诗人客居他乡的思乡之情。</li></ol><hr><p><strong>文档编号</strong>: Chin-Tip-001<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,48)])])}const u=e(r,[["render",i]]);export{p as __pageData,u as default};
